from docx import Document

# 读取变更协议一（2024年版）
doc1 = Document("/Users/orion/Documents/大都会-云支付改造/建浩变更协议/《上海轨道交通云支付改造项目施工监理合同》变更协议.docx")
print("===== 变更协议一（2024年版）=====")
for i, p in enumerate(doc1.paragraphs):
    if p.text.strip():
        print(f"P{i}: [{p.style.name}] {p.text}")

print("\n--- 表格 ---")
for ti, table in enumerate(doc1.tables):
    print(f"\n表格{ti}:")
    for ri, row in enumerate(table.rows):
        cells = [cell.text for cell in row.cells]
        print(f"  行{ri}: {cells}")

